import { scope } from "arktype";

export const types = scope({
    node: "file | directory",
    file: {
        name: "string>0",
        "size?": "number%1>0",
        "+": "reject"
    },
    directory: {
        name: "string>0",
        "children?": "node[]",
        "+": "reject"
    }
}).export();

export function validateDirectoryTree(input: unknown) {
    return types.node.assert(input);
}

import { validateDirectoryTree } from "./src/validator.js";

async function readStdin() {
    let data = "";
    for await (const chunk of process.stdin) {
        data += chunk;
    }
    return data;
}

async function main() {
    try {
        const inputStr = await readStdin();
        if (!inputStr.trim()) {
             console.log("INVALID: empty input");
             process.exit(0);
        }
        const input = JSON.parse(inputStr);
        const validated = validateDirectoryTree(input);
        console.log("VALID");
        console.log(JSON.stringify(validated));
    } catch (e: any) {
        console.log(`INVALID: ${e.message}`);
    }
}

main();

